  583: {t:"Quelle est la signification de ce panneau?",a:["Stationnement uniquement pour véhicules non-motorisés","L'arrêt de tout véhicule est interdit, sauf pour faire descendre et monter des passagers","Station pour transport de soldats, uniquement pour les faire monter et descendre des passagers","Stationnement pour véhicules"],c:3},
  584: {t:"Quelle est la limite de validité de ce panneau?",a:["Jusqu'au panneau interdisant l'entrée","Jusqu'au panneau \"Fin de route urbaine\"","Jusqu'au prochain échangeur","Jusqu'à la prochaine intersection ou jusqu'à un endroit où le stationnement est interdit"],c:3},
  585: {t:"Quelle est la signification de ce panneau?",a:["Station de transport,  l'arrêt est interdit à tout véhicule commercial","Stationnement pour véhicules transportant des soldats","Station pour transport de soldats, uniquement pour les faire monter et descendre (il est interdit d'attendre dans la station)","Station pour transport de soldats. L'arrêt n'y est autorise qu'à des véhicules militaires"],c:2},
