  591: {t:"Comment tourner à gauche en sortant d'une chaussée sur laquelle est placé ce panneau?",a:["Le tournant s'effectuera à partir de la voie la plus à droite","Le tournant s'effectuera à partir de la voie du milieu","De la gauche de la chaussée, à moins qu'il ne soit signalé différemment","Il est interdit de tourner à gauche et il n'est permis de rouler que tout droit"],c:2},
  592: {t:"Quelle est la signification de ce panneau?",a:["La circulation dans la direction signalée par la flèche jaune n'est autorisée  qu'aux véhicules de transports publics","Cédez la priorité sur la route étroite et raide  à la circulation venant de la direction opposée pour tout véhicule motorisé","Ne roulez que tout droit, il est interdit de tourner","Vous avez la priorité sur la route étroite"],c:0},
  593: {t:"Quelle est la signification de ce panneau?",a:["Chemin pour piétons uniquement","Cédez la  priorité  au passage piétonnier banalisé sur la chaussée","Pont suspendu pour piétons","Passage piétonnier 150 mètres devant vous"],c:1},
  594: {t:"Comment conduirez-vous selon ce panneau?",a:["Quand vous conduisez et vous rapprochez du panneau, ralentissez toujours et même arrêtez-vous si besoin est et laissez les piétons terminer de traverser la chaussée en toute sécurité","Avertissez les piétons quand vous vous approchez en klaxonnant fortement et allumez les feux de croisement","Continuez à circuler et prenez soin que les piétonniers vous dégagent la chaussée","Klaxonnez et avertissez les piétons qui se trouvent sur le passage piétonnier"],c:0},
