  596: {t:"Comment faut-il conduire en s'approchant du panneau situé sur la gauche?",a:["Arrêtez-vous avant un passage à niveau","Fin du segment de priorité","Roulez normalement, Vous êtes sur une chaussée qui a la priorité","Cédez la priorité à la circulation sur la route traversière"],c:2},
  597: {t:"Quelle est la signification de ce panneau?",a:["Fin de la chaussée où il y a   la priorité","Vous êtes sur une chaussée où il y a  la priorité","Le stationnement est interdit aux véhicules","Ralentissez et préparez-vous à la possibilité de vous arrêter"],c:0},
