  610: {t:"Quelle est la signification de ce panneau?",a:["Il est interdit à un véhicule commercial de doubler","Il est interdit de doubler un véhicule privé","Fin d'interdiction du segment où il est interdit  à un véhicule commercial de doubler","Il est interdit aux autobus de doubler"],c:2},
  611: {t:"Quand on roule sur une chaussée mouillée, se créée une situation de:",a:["Danger que  le véhicule se renverse à cause d'une petite vitesse","Danger de dérapage et de renversement, qui augmente plus la vitesse est rapide","Danger de dérapage et de renversement, qu'iI est possible d'éviter en accélérant","Distance de réaction  plus longue"],c:1},
  612: {t:"Un véhicule autorisé à transporter des enfants est?",a:["Tout autobus enregistré dans une compagnie de transport","Tout véhicule motorisé qui transporte des enfants","Tout autobus public sur une ligne de service","Un autobus privé ou un véhicule public qui ont été autorisés à transporter des enfants"],c:3},
