  614: {t:"\"Le transport d'élèves\" dans un autobus est?",a:["Tout transport d'un groupe d'élèves dans un autobus même sur une ligne de transport","Le transport d'enfants à l'école ou à une activité organisée dans un véhicule destiné au transport d'élèves","Tout transport d'enfants ou d'étudiants dans  un autobus","Le transport d'enfants jusqu'à 16 ans dans un autobus"],c:1},
