  618: {t:"Jusqu'où est valide le panneau situé devant vous?",a:["Jusqu'au panneau indiquant l'entrée en zone de route urbaine","Jusqu'au prochain passage piétonnier","Jusqu'à la prochaine intersection","150 mètres de l'endroit où est placé le panneau"],c:2},
  619: {t:"Un conducteur de \"véhicule de randonnée\", doit avoir un permis de conduire du type:",a:["B ou C","D1 ou D","A ou B","C1 ou B"],c:1},
