  645: {t:"Comment faut-il continuer à rouler selon cette signalisation?",a:["Il est permis de tourner à gauche de toute voie","Il est permis de rouler tout droit (devant) ou à gauche","Il est permis de rouler uniquement à gauche","Il est permis de rouler uniquement   à droite"],c:1},
  646: {t:"Comment faut-il tourner  à gauche selon cette signalisation?",a:["De la voie de gauche dans la direction de votre circulation","A partir des  deux voies indiquées","Il est absolument interdit de tourner à gauche","Uniquement de la voie de droite"],c:0},
  647: {t:"Que  signifie cette signalisation sur la route?",a:["Ligne d'arrêt, endroit d'arrêt du véhicule quand il y a obligation de s'arrêter","Ligne de stationnement (emplacement de stationnement pour véhicules ou pour animaux)","Ligne d'attente  (à l'endroit où il n'y a pas de panneau)","Emplacement de stationnement pour véhicules devant vous"],c:0},
  648: {t:"Comment devez-vous conduire quand vous vous approchez de cette signalisation sur la route?",a:["Arrêtez-vous toujours, avant la ligne d'arrêt","Arrêtez-vous avant la ligne  quand il y a obligation de s'arrêter","Il est toujours  obligatoire  de s'arrêter en période d'éclairage","Arrêtez-vous uniquement quand la ligne est indiquée avant un passage à niveau"],c:1},
  649: {t:"Que  signifie cette signalisation sur la route?",a:["Passage piétonnier","Passage pour vélo cyclistes","Parking autorisé uniquement pour véhicules publics","Parking de stationnement et places de stationnement pour vélos"],c:0},
  650: {t:"Quel panneau apparaitra après le panneau 708?",a:["716","712","710","709"],c:3},
  651: {t:"Sur votre voie, la flèche sur l'illustration est signalée sur la chaussée. Que signifie la flèche?",a:["Vous devez dévier sur la voie de gauche","Il est permis de doubler à gauche","Deviez sur la voie de gauche maintenant","De cette voie, on est obligé de tourner à gauche à la prochaine intersection"],c:3},
